function agregarSubvista() {
  // Data already includes subvista fields inline
}

function renderSubvista(x) {
  const f = (v) => (!v && v !== 0) ? '—' : '$' + Number(v).toLocaleString('es-CO');
  const cobChips = (x.cob || '').split(',').map(c => c.trim()).filter(Boolean).map(c => '<span class="cob-chip">' + c + '</span>').join('');
  return `
  <div class="subvista">
    <div class="subvista-section">
      <div class="subvista-title"><i class="fa-solid fa-money-bill-wave"></i> Información de Primas</div>
      <div class="subvista-grid">
        <div class="subvista-item"><span class="lbl">Prima sin asistencia</span><span class="val">${f(x.psa)}</span></div>
        <div class="subvista-item"><span class="lbl">Prima con asistencia</span><span class="val">${f(x.pca)}</span></div>
        <div class="subvista-item"><span class="lbl">% IVA</span><span class="val">${x.iva}%</span></div>
        <div class="subvista-item"><span class="lbl">Prima total (con IVA)</span><span class="val">${f(x.pt)}</span></div>
        <div class="subvista-item"><span class="lbl">Código riesgo</span><span class="val">${x.codR || '—'}</span></div>
      </div>
    </div>
    <div class="subvista-section">
      <div class="subvista-title"><i class="fa-solid fa-user-shield"></i> Datos del Asegurado</div>
      <div class="subvista-grid">
        <div class="subvista-item"><span class="lbl">Tipo documento</span><span class="val">${x.tda || '—'}</span></div>
        <div class="subvista-item"><span class="lbl">ID Asegurado</span><span class="val">${x.ida || '—'}</span></div>
        <div class="subvista-item"><span class="lbl">Nombre</span><span class="val">${x.na || '—'}</span></div>
        <div class="subvista-item"><span class="lbl">Género</span><span class="val">${x.ga || '—'}</span></div>
        <div class="subvista-item"><span class="lbl">Fecha nacimiento</span><span class="val">${x.fn || '—'}</span></div>
        <div class="subvista-item"><span class="lbl">Edad</span><span class="val">${x.ea || '—'}</span></div>
        ${x.tdap ? '<div class="subvista-item"><span class="lbl">Tipo doc. principal</span><span class="val">'+x.tdap+'</span></div>' : ''}
        ${x.ndap && x.ndap !== '—' ? '<div class="subvista-item"><span class="lbl">N° doc. principal</span><span class="val">'+x.ndap+'</span></div>' : ''}
        ${x.nap && x.nap !== '—' ? '<div class="subvista-item"><span class="lbl">Nombre principal</span><span class="val">'+x.nap+'</span></div>' : ''}
      </div>
    </div>
    <div class="subvista-section" style="grid-column:1/-1">
      <div class="subvista-title"><i class="fa-solid fa-shield-halved"></i> Coberturas por Póliza</div>
      <div class="cob-list">${cobChips}</div>
    </div>
  </div>`;
}

function toggleSubvista(idx) {
  const row = document.getElementById('sub-' + idx);
  if (row) { row.remove(); return; }
  const tr = document.getElementById('row-' + idx);
  const x = D[idx];
  const colCount = document.querySelectorAll('#tbl-h th').length;
  const newRow = document.createElement('tr');
  newRow.id = 'sub-' + idx;
  newRow.className = 'subvista-row';
  newRow.innerHTML = '<td colspan="' + colCount + '">' + renderSubvista(x) + '</td>';
  tr.after(newRow);
}
